CREATE VIEW "public"."published_posts_view" AS (select distinct on ("posts"."id") "posts"."id", "posts"."slug", "users"."id" as "author_id", "users"."name" as "author_name", "users"."display_name" as "author_display_name", "post_contents"."title" as "title", "post_contents"."description" as "description", "post_contents"."content" as "content", "tag_agg", "original_post_contents"."published_at", "post_contents"."published_at" as "updated_at", "has_draft" from "posts" inner join "users" on "posts"."author_id" = "users"."id" inner join "post_contents" on "posts"."id" = "post_contents"."post_id" left join lateral (select COALESCE(JSON_AGG(JSON_BUILD_OBJECT('name', "tags"."name", 'slug', "tags"."slug")), '[]'::JSON) as "tag_agg" from "post_tags" inner join "tags" on "post_tags"."tag_id" = "tags"."id" where "post_tags"."post_id" = "posts"."id") "tags" on TRUE left join lateral (select "published_at" from "post_contents" where "post_contents"."post_id" = "posts"."id" order by "post_contents"."identifier" asc limit 1) "original_post_contents" on TRUE left join lateral (select "published_at" is null as "has_draft" from "post_contents" where "post_contents"."post_id" = "posts"."id" order by "post_contents"."identifier" desc limit 1) "draft_query" on TRUE where ("posts"."is_private" <> true and "post_contents"."is_private" <> true and "post_contents"."published_at" is not null) order by "posts"."id" desc, "post_contents"."identifier" desc);